from __future__ import annotations

from dataclasses import asdict, dataclass
from datetime import datetime


@dataclass
class CheckpointMetadata:
    run_id: str
    step: int
    stage: str
    notes: str
    created_at: str


def build_checkpoint_metadata(run_id: str, step: int) -> dict[str, str | int]:
    metadata = CheckpointMetadata(
        run_id=run_id,
        step=step,
        stage="windows_cuda",
        notes="project-authored synthetic educational example",
        created_at=datetime.now().isoformat(timespec="seconds"),
    )
    return asdict(metadata)


def main() -> None:
    print(build_checkpoint_metadata("demo_run", step=100))


if __name__ == "__main__":
    main()

from __future__ import annotations

from pathlib import Path


def validate_config_shape(config: dict) -> list[str]:
    errors: list[str] = []
    if not isinstance(config.get("model"), dict):
        errors.append("model section missing")
    if not isinstance(config.get("training"), dict):
        errors.append("training section missing")
    if not isinstance(config.get("tokenizer"), dict):
        errors.append("tokenizer section missing")
    return errors


def validate_tokenizer_path(config: dict, repo_root: Path) -> list[str]:
    tokenizer = config.get("tokenizer", {})
    path_value = tokenizer.get("path")
    if not isinstance(path_value, str):
        return ["tokenizer.path missing"]
    resolved = repo_root / path_value
    return [] if resolved.exists() else [f"missing tokenizer path: {resolved}"]


def main() -> None:
    example = {
        "model": {"vocab_size": 1846},
        "training": {"max_steps": 100},
        "tokenizer": {"path": "tokenizers/example/tokenizer.json"},
    }
    print(validate_config_shape(example))


if __name__ == "__main__":
    main()

from __future__ import annotations


def normalize_text(raw_text: str) -> str:
    cleaned_lines: list[str] = []
    for line in raw_text.replace("\r\n", "\n").replace("\r", "\n").split("\n"):
        cleaned_lines.append(line.rstrip())
    cleaned_text = "\n".join(cleaned_lines).strip()
    return cleaned_text


def is_meaningful_text(text: str) -> bool:
    return bool(text and text.strip())


def main() -> None:
    sample = "  line one  \r\nline two\r\n\r\n"
    cleaned = normalize_text(sample)
    print(cleaned)
    print(is_meaningful_text(cleaned))


if __name__ == "__main__":
    main()

from __future__ import annotations

import json
from pathlib import Path


def read_train_losses(path: Path) -> list[float]:
    losses: list[float] = []
    with path.open("r", encoding="utf-8") as handle:
        for line in handle:
            if not line.strip():
                continue
            record = json.loads(line)
            value = record.get("train_loss")
            if isinstance(value, (int, float)):
                losses.append(float(value))
    return losses


def summarize_losses(losses: list[float]) -> dict[str, float]:
    return {
        "first": losses[0],
        "final": losses[-1],
        "min": min(losses),
        "max": max(losses),
    }


def main() -> None:
    demo_path = Path("metrics_example.jsonl")
    if demo_path.exists():
        print(summarize_losses(read_train_losses(demo_path)))


if __name__ == "__main__":
    main()
